css:
.loader {
  width: 224px;
  height: 256px;
  border-radius: 18px;
  padding: 16px;
  display: flex;
  flex-direction: column;
  gap: 16px;
  background: #d4d4d4;
}
.thumbnail,
.rows span {
  background: linear-gradient(90deg, rgba(115,115,115,.22), rgba(255,255,255,.35), rgba(115,115,115,.22));
  background-size: 300% 100%;
  animation: skeletonSweep 1.2s ease-in-out infinite;
  border-radius: 10px;
}
.thumbnail { width: 100%; height: 128px; }
.rows { display: flex; flex-direction: column; gap: 10px; }
.rows span { height: 14px; width: 100%; }
.rows span:nth-child(2) { width: 80%; }
.rows span:nth-child(4) { width: 50%; }
@keyframes skeletonSweep { to { background-position: -300% 0; } }
